"use client";
/* ==========================================================================
   Aura — React hooks

   Optional utilities for React apps using Aura. Each hook is standalone;
   import only what you need:

     import { useAuraTheme, useAuraTokens } from "@aura-design/core/bindings/react/hooks";
   ========================================================================== */
import { useState, useEffect, useCallback, useMemo, useRef } from "react";
/* The build-emitted resolved token map (dist/aura-tokens.js, generated by
   build.py from tokens.resolved.json — #415). A static ESM import, so it
   works in every bundler and in Node ESM; the module is pure data and not
   listed in `sideEffects`, so apps that never call useAuraTokens tree-shake
   it away. Relative (not a self-referencing package specifier) so it resolves
   identically from npm, git, and submodule installs. */
import { auraTokens } from "../../dist/aura-tokens.js";

/* -------------------------------------------------------------------------- */
/* useAuraTheme                                                                 */
/* -------------------------------------------------------------------------- */

/* MODE axis — dark / light / auto (data-aura-theme). */
const THEME_ATTR = "data-aura-theme";
/* NAMED-THEME axis — default / warm-dusk / … (data-aura-theme-name). A theme is
   ONLY a named token set, so flipping it changes nearly every --aura-* value
   (theming-and-configuration-design.md §7). The token-reading hooks must watch
   it (#570) or they return stale values after a named-theme switch. */
const THEME_NAME_ATTR = "data-aura-theme-name";
const THEME_KEY  = "aura-theme";

/* Aura's three-knob theming also exposes primary/secondary accent overrides
   (aura-app `primary`/`secondary`). A token like `--aura-primary` can change
   when these change WITHOUT data-aura-theme changing, so the token-reading
   hooks must observe them too (#525). The named-theme axis (#570) is the axis
   that actually carries the colour tokens, so it is observed too. */
const ACCENT_ATTRS = ["primary", "secondary"];
const THEME_OBSERVED_ATTRS = [THEME_ATTR, THEME_NAME_ATTR, ...ACCENT_ATTRS];

/* (#579) Persistence interop with the vanilla runtime (Aura.theme.persist,
   js/theme.js): BOTH layers default to the localStorage key "aura-theme" and
   the native side reads/writes the JSON shape `{ theme, mode }` (theme = the
   NAMED theme, mode = dark/light). The React hook must use the SAME shape so a
   value one layer writes is read correctly by the other — a bare-string write
   from the hook would make Aura's `JSON.parse` yield a non-object (corrupting
   restore), and a JSON-object write from Aura would leak as a literal string
   into `data-aura-theme`. These helpers are the single read/write of that shape;
   they fail soft (storage may be unavailable / malformed). */
function readPersisted() {
  try {
    var parsed = JSON.parse(localStorage.getItem(THEME_KEY) || "null");
    return parsed && typeof parsed === "object" ? parsed : null;
  } catch (_) {
    return null;
  }
}

/* Merge a partial `{ theme?, mode? }` into the shared key, preserving the other
   axis the caller did not touch (so persisting a mode never drops a named theme,
   and vice versa). */
function writePersisted(patch) {
  try {
    const current = readPersisted() || {};
    localStorage.setItem(THEME_KEY, JSON.stringify(Object.assign({}, current, patch)));
  } catch (_) {}
}

/* Reflect a theme onto <html> + local state WITHOUT persisting (#520): a
   cross-tab `storage` sync is not a user action, so it must not re-write
   localStorage (which would otherwise echo the same value back on every
   tab). The persisting setter (setTheme) layers the localStorage write on top
   of this shared reflect. */
function applyTheme(next, setThemeState) {
  if (typeof document !== "undefined") {
    document.documentElement.setAttribute(THEME_ATTR, next);
  }
  setThemeState(next);
}

/**
 * Reads and controls the active Aura theme (`data-aura-theme` on `<html>`).
 *
 * SCOPE — this hook owns the MODE axis (`data-aura-theme`: dark/light/auto).
 * The orthogonal NAMED-theme axis (`data-aura-theme-name`) is owned by the
 * sibling {@link useAuraThemeName} hook (#570).
 *
 * - Returns `[theme, setTheme]` where `theme` is the current value.
 * - Persists the selection to `localStorage` under `"aura-theme"`, in the SAME
 *   `{ theme, mode }` JSON shape the vanilla `Aura.theme.persist()` uses (#579),
 *   so the two layers interoperate instead of corrupting each other; the hook
 *   writes only the `mode` field and preserves any persisted named `theme`.
 * - Syncs across tabs via the `storage` event.
 * - Server-safe AND hydration-safe (#470): the FIRST render — on the server
 *   and on the client — is always `defaultTheme`, so the client's initial
 *   markup matches the server's even when an anti-flash inline script has
 *   already set `data-aura-theme` on `<html>`. The hook reconciles to the
 *   live attribute in an effect (post-hydration), then tracks it live.
 *
 * @param {string} [defaultTheme="dark"]
 * @returns {[string, (theme: string) => void]}
 */
export function useAuraTheme(defaultTheme = "dark") {
  /* (#470) Initialize to defaultTheme unconditionally — reading the live DOM
     here would diverge from the server render and trigger a hydration
     mismatch. The effect below snaps to the real attribute after hydration. */
  const [theme, setThemeState] = useState(defaultTheme);

  const setTheme = useCallback((next) => {
    /* A user-driven change: reflect AND persist. Persist as the shared
       `{ theme, mode }` shape (#579) — write only `mode`, preserving any named
       theme the vanilla layer stored. */
    applyTheme(next, setThemeState);
    writePersisted({ mode: next });
  }, []);

  useEffect(() => {
    /* (#470) Post-hydration reconcile: snap to the live attribute set by the
       anti-flash inline script before React booted. Runs once on mount, then
       the observer tracks subsequent changes. */
    const initial = document.documentElement.getAttribute(THEME_ATTR) ?? defaultTheme;
    setThemeState(initial);

    /* Reflect any programmatic changes made outside React (e.g. Aura's own
       theme switcher component) back into the hook state. */
    const observer = new MutationObserver(() => {
      const current = document.documentElement.getAttribute(THEME_ATTR) ?? defaultTheme;
      setThemeState(current);
    });
    observer.observe(document.documentElement, {
      attributes: true,
      attributeFilter: [THEME_ATTR],
    });

    /* Cross-tab sync. A `storage` event is a REFLECT of another tab's change,
       not a user action — apply attribute + state only, never re-persist
       (#520): re-writing the same value to localStorage just echoes it back to
       every other tab and would spuriously fire any future setTheme side
       effect on each sync. */
    const onStorage = (e) => {
      if (e.key !== THEME_KEY || !e.newValue) return;
      /* (#579) The shared value is `{ theme, mode }` JSON — read the mode field
         (this hook's axis); ignore malformed / mode-less writes. */
      let mode;
      try { mode = (JSON.parse(e.newValue) || {}).mode; } catch (_) {}
      if (mode) applyTheme(mode, setThemeState);
    };
    window.addEventListener("storage", onStorage);

    return () => {
      observer.disconnect();
      window.removeEventListener("storage", onStorage);
    };
  }, [defaultTheme]);

  return [theme, setTheme];
}

/* -------------------------------------------------------------------------- */
/* useAuraThemeName                                                             */
/* -------------------------------------------------------------------------- */

/* The named-theme axis treats a missing attribute as the base look "default"
   (mirrors Aura.theme.getTheme / setTheme in js/theme.js). */
const DEFAULT_THEME_NAME = "default";

/* Reflect a named theme onto <html> WITHOUT persisting (the cross-tab / observer
   path), mirroring applyTheme for the mode axis. "default" (or empty) removes
   the attribute — restoring the base look — exactly as Aura.theme.setTheme does. */
function applyThemeName(next, setNameState) {
  if (typeof document !== "undefined") {
    const root = document.documentElement;
    if (!next || next === DEFAULT_THEME_NAME) root.removeAttribute(THEME_NAME_ATTR);
    else root.setAttribute(THEME_NAME_ATTR, next);
  }
  setNameState(next || DEFAULT_THEME_NAME);
}

/**
 * Reads and controls the active NAMED theme (`data-aura-theme-name` on
 * `<html>`) — the axis the vanilla `Aura.theme.setTheme()` flips and the one
 * that actually carries the colour tokens (#570). Orthogonal to
 * {@link useAuraTheme}, which owns the dark/light MODE axis.
 *
 * - Returns `[themeName, setThemeName]`; `"default"` when no named theme is set.
 * - Persists to the SAME `{ theme, mode }` JSON key as the mode hook and the
 *   vanilla persistence (#579), writing only the `theme` field.
 * - Hydration-safe like {@link useAuraTheme}: first render is `defaultName`,
 *   then an effect reconciles to the live attribute and tracks it.
 * - Syncs across tabs via the `storage` event.
 *
 * @param {string} [defaultName="default"]
 * @returns {[string, (name: string) => void]}
 */
export function useAuraThemeName(defaultName = DEFAULT_THEME_NAME) {
  const [name, setNameState] = useState(defaultName);

  const setThemeName = useCallback((next) => {
    applyThemeName(next, setNameState);
    writePersisted({ theme: next || DEFAULT_THEME_NAME });
  }, []);

  useEffect(() => {
    /* (#623) Reconcile to the live attribute, falling back to `defaultName` when
       no named theme is set — mirroring the sibling `useAuraTheme` effect, which
       uses `?? defaultTheme`. Depending on `[defaultName]` (matching
       `useAuraTheme`'s `[defaultTheme]`) means a changing default is honoured
       consistently across both hooks. */
    const read = () =>
      document.documentElement.getAttribute(THEME_NAME_ATTR) || defaultName;
    setNameState(read());

    const observer = new MutationObserver(() => setNameState(read()));
    observer.observe(document.documentElement, {
      attributes: true,
      attributeFilter: [THEME_NAME_ATTR],
    });

    const onStorage = (e) => {
      if (e.key !== THEME_KEY || !e.newValue) return;
      let next;
      try { next = (JSON.parse(e.newValue) || {}).theme; } catch (_) {}
      if (next) applyThemeName(next, setNameState);
    };
    window.addEventListener("storage", onStorage);

    return () => {
      observer.disconnect();
      window.removeEventListener("storage", onStorage);
    };
  }, [defaultName]);

  return [name, setThemeName];
}

/* -------------------------------------------------------------------------- */
/* useAuraTokens                                                                */
/* -------------------------------------------------------------------------- */

/**
 * Returns the Aura token map (memoized, stable reference).
 *
 * Backed by the build-emitted `dist/aura-tokens.js` ESM module. For static
 * usage outside a component, importing `auraTokens` from that module
 * directly is equivalent.
 *
 * Keys are camelCase, UNPREFIXED build-time names (`accent`, `avatarLg`,
 * `bg2`) — a distinct namespace from `useAuraCSSToken`, which takes the
 * `--aura-*` CSS custom-property name. `useAuraTokens()["--aura-primary"]`
 * is `undefined`; use `useAuraTokens().primary` or `useAuraCSSToken(
 * "--aura-primary")` (#469). The d.ts narrows keys to the generated literal
 * type, so a typo'd key is a compile error.
 *
 * @returns {typeof import("../../dist/aura-tokens.js").auraTokens} Frozen token map.
 */
export function useAuraTokens() {
  /* The token map is a frozen module-level constant (pre-resolved at build
     time), so this is a stable reference — SSR-safe, no effect needed. */
  return useMemo(() => auraTokens, []);
}

/**
 * Reads a single resolved Aura CSS custom property from the document root.
 *
 * Useful when you need a token value as a JS string at runtime (e.g. for
 * Canvas rendering or third-party charting libraries).
 *
 * Server-safe AND hydration-safe (#658): the FIRST render — on the server and
 * the client's hydration render alike — returns `""`; the mount effect then
 * reads the real value, matching the #470 fix for {@link useAuraTheme}.
 *
 * Re-reads when the theme OR an accent override changes (#525): besides
 * `data-aura-theme`, Aura's three-knob theming exposes primary/secondary
 * accent overrides (`aura-app primary=…` mirrors them to `--aura-primary` /
 * `--aura-secondary` inline styles), so the observer also watches the accent
 * attributes and the root `style` — otherwise a `--aura-primary` change with
 * no theme switch would leave a stale value.
 *
 * @param {string} property  CSS custom property name, e.g. `"--aura-primary"`.
 * @returns {string}
 */
export function useAuraCSSToken(property) {
  /* (#658) Initialize to "" unconditionally — reading the live DOM via
     getComputedStyle here makes the client's first (hydration) render diverge
     from the server's "" and triggers a React hydration mismatch, the exact
     bug #470 fixed for useAuraTheme. The mount effect below is the single
     source of the first real value, so server and client first renders agree. */
  const [value, setValue] = useState("");

  useEffect(() => {
    const read = () =>
      getComputedStyle(document.documentElement)
        .getPropertyValue(property)
        .trim();

    setValue(read());

    const observer = new MutationObserver(() => setValue(read()));
    observer.observe(document.documentElement, {
      attributes: true,
      /* theme + accent attributes + the inline style the accent overrides land
         in (#525), so an accent change without a theme switch still refreshes. */
      attributeFilter: [...THEME_OBSERVED_ATTRS, "style"],
    });
    return () => observer.disconnect();
  }, [property]);

  return value;
}

/* -------------------------------------------------------------------------- */
/* useAuraMotion                                                                */
/* -------------------------------------------------------------------------- */

/**
 * Returns whether the user has requested reduced motion.
 *
 * Reactive — updates when the system preference changes.
 *
 * @returns {boolean} `true` when `prefers-reduced-motion: reduce` is active.
 */
export function useAuraMotion() {
  const query = "(prefers-reduced-motion: reduce)";
  const [reduced, setReduced] = useState(() =>
    typeof window !== "undefined"
      ? window.matchMedia(query).matches
      : false
  );

  useEffect(() => {
    const mq = window.matchMedia(query);
    const handler = (e) => setReduced(e.matches);
    mq.addEventListener("change", handler);
    return () => mq.removeEventListener("change", handler);
  }, []);

  return reduced;
}

/* -------------------------------------------------------------------------- */
/* useAuraMediaQuery                                                            */
/* -------------------------------------------------------------------------- */

/**
 * Reactive wrapper around `window.matchMedia`.
 *
 * @param {string} query  A CSS media query string.
 * @returns {boolean}
 */
export function useAuraMediaQuery(query) {
  const [matches, setMatches] = useState(() =>
    typeof window !== "undefined"
      ? window.matchMedia(query).matches
      : false
  );

  useEffect(() => {
    const mq = window.matchMedia(query);
    const handler = (e) => setMatches(e.matches);
    mq.addEventListener("change", handler);
    setMatches(mq.matches);
    return () => mq.removeEventListener("change", handler);
  }, [query]);

  return matches;
}

/* -------------------------------------------------------------------------- */
/* useAuraEvent                                                                 */
/* -------------------------------------------------------------------------- */

/**
 * Attaches a typed Aura custom-event listener to a ref'd element.
 *
 * Equivalent to the `events` prop on Aura wrapper components, but usable with
 * any element ref — including raw DOM refs or portaled elements.
 *
 * @param {React.RefObject<HTMLElement>} ref
 * @param {string} eventName
 * @param {(e: CustomEvent) => void} handler
 *
 * @example
 * ```tsx
 * const editorRef = useRef(null);
 * useAuraEvent(editorRef, "aura:change", (e) => setHtml(e.detail.html));
 * ```
 */
export function useAuraEvent(ref, eventName, handler) {
  const savedHandler = useRef(handler);
  useEffect(() => { savedHandler.current = handler; }, [handler]);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const listener = (e) => savedHandler.current(e);
    el.addEventListener(eventName, listener);
    return () => el.removeEventListener(eventName, listener);
  }, [ref, eventName]);
}

/* -------------------------------------------------------------------------- */
/* useAuraDarkMode                                                              */
/* -------------------------------------------------------------------------- */

/* The mode axis (data-aura-theme) takes exactly dark / light / auto (#574);
   `auto` follows the OS via prefers-color-scheme. The brand-theme "aura" is a
   NAMED theme (data-aura-theme-name), never a value of this axis, so the old
   `["dark", "aura"]` membership test could never match — it was written against
   a misunderstanding of the two-axis model and is removed. */
const DARK_MODE = "dark";
const LIGHT_MODE = "light";
const AUTO_MODE = "auto";
const DARK_SCHEME_QUERY = "(prefers-color-scheme: dark)";

/**
 * Convenience wrapper for the common dark/light toggle, on the MODE axis.
 *
 * SCOPE — the dark/light binary derived from `data-aura-theme` (#574):
 * - `dark`  → `isDark === true`
 * - `light` → `isDark === false`
 * - `auto`  → resolved against the OS `prefers-color-scheme` (reactive): a dark
 *   OS reports `isDark === true` even though the attribute reads `auto` — the
 *   bug this fix closes (it previously reported light in a dark OS).
 *
 * `setDark(true|false)` writes the explicit `dark`/`light` mode; `toggle()`
 * flips the CURRENTLY EFFECTIVE state (so toggling from `auto` in a dark OS
 * goes to `light`, as a user expects).
 *
 * @returns {{ isDark: boolean, toggle: () => void, setDark: (v: boolean) => void }}
 */
export function useAuraDarkMode() {
  const [theme, setTheme] = useAuraTheme(DARK_MODE);

  /* Track the OS preference reactively so an `auto` mode re-resolves when the
     system flips dark/light (and so isDark is correct from first effect). */
  const systemDark = useAuraMediaQuery(DARK_SCHEME_QUERY);

  const isDark = theme === AUTO_MODE ? systemDark : theme === DARK_MODE;

  const setDark = useCallback(
    (v) => setTheme(v ? DARK_MODE : LIGHT_MODE),
    [setTheme]
  );
  const toggle = useCallback(
    () => setDark(!isDark),
    [isDark, setDark]
  );
  return { isDark, toggle, setDark };
}

/* -------------------------------------------------------------------------- */
/* useAuraToast                                                                 */
/* -------------------------------------------------------------------------- */

/**
 * Returns a stable `showToast(input)` callback that imperatively fires a toast
 * via the Aura runtime (`window.Aura.toast()`), without requiring the caller to
 * touch `window` directly.
 *
 * SSR-safe: the callback guards with `typeof window !== "undefined"` before
 * calling `window.Aura.toast`, so it is safe to invoke server-side (no-ops).
 *
 * The callback reference is stable across renders (empty `useCallback` deps),
 * so it can be passed to memoized children without triggering re-renders.
 *
 * `Aura.toast` signature: `toast(message | { message, variant?, duration?, onClose? }) → Element`
 *
 * @returns {{ showToast: (input: string | { message: string, variant?: string, duration?: number, onClose?: Function }) => Element }}
 *
 * @example
 * ```tsx
 * const { showToast } = useAuraToast();
 * <button onClick={() => showToast({ message: "Saved!", variant: "success" })}>
 *   Save
 * </button>
 * ```
 */
export function useAuraToast() {
  const showToast = useCallback((input) => {
    if (typeof window !== "undefined" && window.Aura && window.Aura.toast) {
      return window.Aura.toast(input);
    }
  }, []);
  return { showToast };
}

/* -------------------------------------------------------------------------- */
/* useAuraAccentColor                                                           */
/* -------------------------------------------------------------------------- */

/**
 * Reactive read/write for the Aura primary accent colour (`--aura-primary`).
 *
 * Aura's three-knob theming exposes the primary accent on two independent axes:
 *   1. TOKEN LAYER — `--aura-primary` resolves from the active named theme
 *      (`data-aura-theme-name`). Switching named themes changes the token.
 *   2. OVERRIDE LAYER — `Aura.theme.setPrimary(hex)` writes `--aura-primary`
 *      as an inline style on `<html>`, superseding the token-layer value.
 *      `setColor` delegates to this API.
 *
 * `color` is the live computed value of `--aura-primary` (empty string during
 * SSR / before mount — hydration-safe per #658). The hook watches
 * `data-aura-theme`, `data-aura-theme-name`, accent attributes, and the root
 * `style` attribute via MutationObserver (#525), so it stays reactive across
 * both axes without polling.
 *
 * @returns {[color: string, setColor: (hex: string) => void]}
 */
export function useAuraAccentColor() {
  const color = useAuraCSSToken("--aura-primary");
  const setColor = useCallback((hex) => {
    if (typeof window !== "undefined" && window.Aura && window.Aura.theme) {
      window.Aura.theme.setPrimary(hex);
    }
  }, []);
  return [color, setColor];
}

/* -------------------------------------------------------------------------- */
/* useAuraSecondaryColor                                                        */
/* -------------------------------------------------------------------------- */

/**
 * Reactive read/write for the Aura secondary accent colour (`--aura-secondary`).
 *
 * Symmetric counterpart to {@link useAuraAccentColor} for the secondary accent
 * axis. `color` is the live computed value of `--aura-secondary` (empty string
 * during SSR / before mount). `setColor(hex)` delegates to
 * `Aura.theme.setSecondary(hex)`, which writes `--aura-secondary` as an inline
 * style on `<html>`, superseding any token-layer value.
 *
 * @returns {[color: string, setColor: (hex: string) => void]}
 */
export function useAuraSecondaryColor() {
  const color = useAuraCSSToken("--aura-secondary");
  const setColor = useCallback((hex) => {
    if (typeof window !== "undefined" && window.Aura && window.Aura.theme) {
      window.Aura.theme.setSecondary(hex);
    }
  }, []);
  return [color, setColor];
}

/* -------------------------------------------------------------------------- */
/* useAuraSuggestPalette                                                        */
/* -------------------------------------------------------------------------- */

/**
 * Suggests a harmonious secondary colour derived from a primary accent.
 *
 * Delegates to {@link Aura.theme.suggestPalette} which rotates the primary's
 * OKLCH hue by 180° to produce a complementary secondary. Memoised on `primary`.
 *
 * SSR-safe: returns `null` when `window` / the Aura colour module is absent.
 *
 * @param {string} primary  Hex colour string for the primary accent (e.g. `"#6366f1"`).
 * @returns {{ secondary: string } | null}  Object with the suggested secondary hex,
 *   or `null` if the colour module is unavailable.
 */
export function useAuraSuggestPalette(primary) {
  return useMemo(function () {
    if (
      typeof window === "undefined" ||
      !window.Aura ||
      !window.Aura.theme ||
      typeof window.Aura.theme.suggestPalette !== "function"
    ) {
      return null;
    }
    try {
      return window.Aura.theme.suggestPalette(primary);
    } catch (_) {
      return null;
    }
  }, [primary]);
}

/* -------------------------------------------------------------------------- */
/* useAuraDialog                                                                */
/* -------------------------------------------------------------------------- */

/**
 * Imperatively controls an `<AuraDialog>` element and tracks its open/closed
 * state.
 *
 * Wraps `Aura.dialog.open()` / `.close()` and listens to the
 * `aura:dialog-open` / `aura:dialog-close` events so `isOpen` stays in sync
 * even when the dialog closes via ESC, scrim click, or a close button inside.
 *
 * @param {React.RefObject<HTMLElement>} ref  Ref attached to the `<AuraDialog>` element.
 * @returns {{ isOpen: boolean, open: (opener?: Element | null) => void, close: () => void }}
 *   Pass an `opener` element to `open()` so the dialog runtime returns focus there on close.
 *
 * `isOpen` is seeded from the `open` attribute on mount; `false` only during SSR.
 *
 * @example
 * ```tsx
 * const dialogRef = useRef(null);
 * const triggerRef = useRef(null);
 * const { isOpen, open, close } = useAuraDialog(dialogRef);
 * return (
 *   <>
 *     {/* Pass the trigger ref to open() so focus returns there on close (a11y) *\/}
 *     <AuraButton ref={triggerRef} onClick={() => open(triggerRef.current)}>
 *       Open dialog
 *     </AuraButton>
 *     <AuraDialog ref={dialogRef} aria-label="Example dialog">
 *       <p>Is open: {String(isOpen)}</p>
 *       <AuraButton onClick={close}>Close</AuraButton>
 *     </AuraDialog>
 *   </>
 * );
 * ```
 */
export function useAuraDialog(ref) {
  const [isOpen, setIsOpen] = useState(false);

  useEffect(function () {
    const el = ref && ref.current;
    if (!el) return;
    // Seed initial open state from the element attribute on mount.
    setIsOpen(el.hasAttribute("open"));
    function onOpen() { setIsOpen(true); }
    function onClose() { setIsOpen(false); }
    el.addEventListener("aura:dialog-open", onOpen);
    el.addEventListener("aura:dialog-close", onClose);
    return function () {
      el.removeEventListener("aura:dialog-open", onOpen);
      el.removeEventListener("aura:dialog-close", onClose);
    };
  }, [ref]);

  const open = useCallback(function (opener) {
    const el = ref && ref.current;
    if (el && typeof window !== "undefined" && window.Aura && window.Aura.dialog) {
      window.Aura.dialog.open(el, opener != null ? opener : undefined);
    }
  }, [ref]);

  const close = useCallback(function () {
    const el = ref && ref.current;
    if (el && typeof window !== "undefined" && window.Aura && window.Aura.dialog) {
      window.Aura.dialog.close(el);
    }
  }, [ref]);

  return { isOpen, open, close };
}

/* -------------------------------------------------------------------------- */
/* useAuraTabs                                                                  */
/* -------------------------------------------------------------------------- */

/**
 * Tracks the active tab index in an `<aura-tabs>` container and allows
 * programmatic tab selection.
 *
 * Listens for `aura:tab-change` events (which bubble from `<aura-tab>`
 * elements) to keep `activeIndex` in sync with every user- and code-driven
 * tab change. On mount the hook reads the initial `<aura-tab[selected]>`
 * attribute so the first render reflects the pre-selected tab rather than -1.
 *
 * @param {React.RefObject<HTMLElement>} ref  Ref attached to the `<aura-tabs>` element.
 * @returns {{ activeIndex: number, selectTab: (index: number) => void }}
 *   `activeIndex` is -1 until the component mounts and a selected tab is found.
 *
 * @example
 * ```tsx
 * const tabsRef = useRef(null);
 * const { activeIndex, selectTab } = useAuraTabs(tabsRef);
 * return (
 *   <>
 *     <AuraTabs ref={tabsRef}>
 *       <AuraTablist>
 *         <AuraTab panel="alpha">Alpha</AuraTab>
 *         <AuraTab panel="beta">Beta</AuraTab>
 *       </AuraTablist>
 *       <AuraTabpanel id="alpha">…</AuraTabpanel>
 *       <AuraTabpanel id="beta">…</AuraTabpanel>
 *     </AuraTabs>
 *     <button onClick={() => selectTab(1)}>Jump to Beta</button>
 *     <p>Active tab: {activeIndex}</p>
 *   </>
 * );
 * ```
 */
export function useAuraTabs(ref) {
  const [activeIndex, setActiveIndex] = useState(-1);
  const [activeTab, setActiveTab] = useState(null);
  const [activePanelId, setActivePanelId] = useState(null);

  useEffect(function () {
    const el = ref && ref.current;
    if (!el) return;
    function getIndex(tabEl) {
      const tabs = Array.from(el.querySelectorAll("aura-tab"));
      return tabs.indexOf(tabEl);
    }
    function syncTab(tabEl) {
      setActiveIndex(getIndex(tabEl));
      setActiveTab(tabEl || null);
      setActivePanelId(tabEl ? (tabEl.getAttribute("aria-controls") || null) : null);
    }
    function onTabChange(e) {
      var tab = e.detail && e.detail.tab;
      syncTab(tab || null);
    }
    el.addEventListener("aura:tab-change", onTabChange);
    const initial = el.querySelector("aura-tab[selected]");
    if (initial) syncTab(initial);
    return function () {
      el.removeEventListener("aura:tab-change", onTabChange);
    };
  }, [ref]);

  const selectTab = useCallback(function (index) {
    const el = ref && ref.current;
    if (!el) return;
    const tabs = el.querySelectorAll("aura-tab");
    const tab = tabs[index];
    if (tab) tab.click();
  }, [ref]);

  return { activeIndex: activeIndex, activeTab: activeTab, activePanelId: activePanelId, selectTab: selectTab };
}

/* -------------------------------------------------------------------------- */
/* useAuraMenu                                                                  */
/* -------------------------------------------------------------------------- */

/**
 * Tracks the open/closed state of an `<aura-menu>` element and exposes
 * convenience wrappers around `Aura.menu.openAtAnchor()` and
 * `Aura.menu.closeAll()`.
 *
 * `isOpen` is kept in sync via a `MutationObserver` watching the element's
 * `class` attribute for the `aura-menu--open` sentinel the menu engine sets.
 * This means every dismiss path — ESC, scrim click, and focus-out — is
 * automatically reflected.
 *
 * `selection` tracks the last `aura:menu-select` event, exposing
 * `{ value, label, checked, action }`. It is `null` before the first selection.
 *
 * @param {React.RefObject<HTMLElement>} ref  Ref attached to the `<aura-menu>` element.
 * @returns {{ isOpen: boolean, openAtAnchor: (anchorEl: HTMLElement) => void, closeAll: () => void, selection: { value: string, label: string, checked: boolean, action: string|null }|null }}
 *
 * @example
 * ```tsx
 * const menuRef = useRef(null);
 * const triggerRef = useRef(null);
 * const { isOpen, openAtAnchor, closeAll, selection } = useAuraMenu(menuRef);
 * return (
 *   <>
 *     <AuraButton ref={triggerRef} onClick={() => openAtAnchor(triggerRef.current)}>
 *       Options
 *     </AuraButton>
 *     <span>isOpen: {String(isOpen)}</span>
 *     {selection && <p>Last picked: {selection.label} ({selection.value})</p>}
 *     <aura-menu ref={menuRef}>
 *       <aura-menu-item value="cut">Cut</aura-menu-item>
 *       <aura-menu-item value="copy">Copy</aura-menu-item>
 *     </aura-menu>
 *   </>
 * );
 * ```
 */
export function useAuraMenu(ref) {
  const [isOpen, setIsOpen] = useState(false);
  const [selection, setSelection] = useState(null);

  useEffect(function () {
    const el = ref && ref.current;
    if (!el) return;
    const obs = new MutationObserver(function () {
      setIsOpen(el.classList.contains("aura-menu--open"));
    });
    obs.observe(el, { attributes: true, attributeFilter: ["class"] });
    setIsOpen(el.classList.contains("aura-menu--open"));
    function onSelect(e) {
      var d = e.detail || {};
      setSelection({
        value: typeof d.value === "string" ? d.value : "",
        label: typeof d.label === "string" ? d.label : "",
        checked: Boolean(d.checked),
        action: typeof d.action === "string" ? d.action : null
      });
    }
    el.addEventListener("aura:menu-select", onSelect);
    return function () {
      obs.disconnect();
      el.removeEventListener("aura:menu-select", onSelect);
    };
  }, [ref]);

  const openAtAnchor = useCallback(function (anchorEl) {
    const el = ref && ref.current;
    if (el && typeof window !== "undefined" && window.Aura && window.Aura.menu) {
      window.Aura.menu.openAtAnchor(el, anchorEl, anchorEl);
    }
  }, [ref]);

  const closeAll = useCallback(function () {
    if (typeof window !== "undefined" && window.Aura && window.Aura.menu) {
      window.Aura.menu.closeAll();
    }
  }, []);

  return { isOpen: isOpen, openAtAnchor: openAtAnchor, closeAll: closeAll, selection: selection };
}

/* -------------------------------------------------------------------------- */
/* useAuraSplit                                                                 */
/* -------------------------------------------------------------------------- */

/**
 * Tracks the live panel size ratios of an `<aura-split>` (resizable splitter)
 * element by subscribing to its `aura:change` events.
 *
 * Returns `ratios` — an array of fr values (positive numbers, one per panel,
 * summing to 100) that updates every time the user drags a split handle.
 * Useful for adapting layout or content based on available panel space.
 *
 * Seeded from the element's live `ratios` getter on mount (non-empty once the
 * element has connected and established its grid template).
 *
 * @param {React.RefObject<HTMLElement>} ref  Ref attached to the `<aura-split>` element.
 * @returns {{ ratios: number[] }}
 *
 * @example
 * ```tsx
 * const splitRef = useRef(null);
 * const { ratios } = useAuraSplit(splitRef);
 * return (
 *   <>
 *     <AuraSplit ref={splitRef} style={{ height: "200px" }}>
 *       <div>Left — {ratios[0]?.toFixed(0) ?? "…"} fr</div>
 *       <div>Right — {ratios[1]?.toFixed(0) ?? "…"} fr</div>
 *     </AuraSplit>
 *     <p>Drag the handle to see ratios update.</p>
 *   </>
 * );
 * ```
 */
export function useAuraSplit(ref) {
  const [ratios, setRatios] = useState([]);

  useEffect(function () {
    const el = ref && ref.current;
    if (!el) return;
    // Seed initial ratios from the element's live `ratios` getter on mount.
    if (typeof el.ratios !== "undefined" && Array.isArray(el.ratios) && el.ratios.length) {
      setRatios(el.ratios.slice());
    }
    function onChange(e) {
      if (e.detail && Array.isArray(e.detail.ratios)) {
        setRatios(e.detail.ratios.slice());
      }
    }
    el.addEventListener("aura:change", onChange);
    return function () {
      el.removeEventListener("aura:change", onChange);
    };
  }, [ref]);

  return { ratios: ratios };
}

/* -------------------------------------------------------------------------- */
/* useAuraDatePicker                                                            */
/* -------------------------------------------------------------------------- */

/**
 * Reads the selected value from an `<aura-datepicker>` element by subscribing
 * to its `aura:change` events.
 *
 * Works for both single-date and range mode:
 * - **Single**: `value` is an ISO date string (e.g. `"2026-06-21"`), `date`
 *   is the corresponding `Date` object, `label` is the localised display string.
 * - **Range**: `value` is `"start/end"` (e.g. `"2026-06-01/2026-06-30"`),
 *   `start` and `end` are the individual ISO strings.
 *
 * `value`, `date`, `start`, and `end` are seeded from the `value` attribute on mount.
 * `label` starts `null` and is populated on the first user selection (no Intl
 * formatter is available at hook time — it only exists inside the element).
 *
 * @param {React.RefObject<HTMLElement>} ref  Ref attached to the `<aura-datepicker>` element.
 * @returns {{ value: string|null, date: Date|null, label: string|null, start: string|null, end: string|null }}
 *
 * @example
 * ```tsx
 * const dpRef = useRef(null);
 * const { value, label } = useAuraDatePicker(dpRef);
 * return (
 *   <>
 *     <AuraDatepicker ref={dpRef} />
 *     <p>Selected: {label ?? "(none)"}</p>
 *   </>
 * );
 * ```
 */
export function useAuraDatePicker(ref) {
  const [value, setValue] = useState(null);
  const [date, setDate] = useState(null);
  const [label, setLabel] = useState(null);
  const [start, setStart] = useState(null);
  const [end, setEnd] = useState(null);

  useEffect(function () {
    const el = ref && ref.current;
    if (!el) return;
    // Seed initial state from the element attribute on mount.
    var initVal = el.getAttribute("value");
    if (initVal) {
      setValue(initVal);
      var slash = initVal.indexOf("/");
      if (slash > -1) {
        // Range mode: "YYYY-MM-DD/YYYY-MM-DD"
        var s = initVal.slice(0, slash), e = initVal.slice(slash + 1);
        setStart(s);
        setEnd(e);
        var sd = new Date(s + "T00:00:00"), ed = new Date(e + "T00:00:00");
        if (!isNaN(sd.getTime())) setDate(sd);
      } else {
        // Single mode
        var pd = new Date(initVal + "T00:00:00");
        if (!isNaN(pd.getTime())) setDate(pd);
      }
    }
    function onChange(e) {
      const d = e.detail || {};
      setValue(d.value || null);
      setDate(d.date instanceof Date ? d.date : null);
      setLabel(d.label || null);
      setStart(d.start || null);
      setEnd(d.end || null);
    }
    el.addEventListener("aura:change", onChange);
    return function () {
      el.removeEventListener("aura:change", onChange);
    };
  }, [ref]);

  return { value: value, date: date, label: label, start: start, end: end };
}

/* -------------------------------------------------------------------------- */
/* useAuraTimePicker                                                            */
/* -------------------------------------------------------------------------- */

/**
 * Reads the selected time value from an `<aura-timepicker>` element by
 * subscribing to its `aura:change` events.
 *
 * `value` is a time string (e.g. `"14:30"`) or `null` before any selection.
 *
 * @param {React.RefObject<HTMLElement>} ref  Ref attached to the `<aura-timepicker>` element.
 * @returns {{ value: string|null }}
 *
 * @example
 * ```tsx
 * const tpRef = useRef(null);
 * const { value } = useAuraTimePicker(tpRef);
 * return (
 *   <>
 *     <AuraTimepicker ref={tpRef} />
 *     <p>Selected: {value ?? "(none)"}</p>
 *   </>
 * );
 * ```
 */
export function useAuraTimePicker(ref) {
  const [value, setValue] = useState(null);

  useEffect(function () {
    const el = ref && ref.current;
    if (!el) return;
    // Seed initial value from the element attribute on mount.
    var initVal = el.getAttribute("value");
    if (initVal) setValue(initVal);
    function onChange(e) {
      const d = e.detail || {};
      setValue(d.value || null);
    }
    el.addEventListener("aura:change", onChange);
    return function () {
      el.removeEventListener("aura:change", onChange);
    };
  }, [ref]);

  return { value: value };
}

/* -------------------------------------------------------------------------- */
/* useAuraColorPicker                                                           */
/* -------------------------------------------------------------------------- */

/**
 * Reads the selected colour from an `<aura-color-picker>` element by subscribing
 * to its `aura:change` events.
 *
 * Returns the full colour payload:
 * - `value` — hex string (e.g. `"#6366f1"` or `"#6366f180"` when alpha < 1).
 * - `rgb` — `{ r, g, b }` (each 0–255).
 * - `hsl` — `{ h, s, l }` (h: 0–360, s/l: 0–100).
 * - `oklch` — `{ l, c, h }` (l: 0–1, c: 0–0.4, h: 0–360).
 * - `alpha` — 0–1 float (1 = fully opaque).
 *
 * All fields are seeded on mount from the `value` attribute via `Aura.color.parseColor()`.
 * They are `null` only during SSR or when no initial `value` attribute is set.
 *
 * @param {React.RefObject<HTMLElement>} ref  Ref attached to the `<aura-color-picker>` element.
 * @returns {{ value: string|null, rgb: {r:number,g:number,b:number}|null, hsl: {h:number,s:number,l:number}|null, oklch: {l:number,c:number,h:number}|null, alpha: number|null }}
 *
 * @example
 * ```tsx
 * const cpRef = useRef(null);
 * const { value, rgb, oklch } = useAuraColorPicker(cpRef);
 * return (
 *   <>
 *     <AuraColorPicker ref={cpRef} value="#6366f1" />
 *     <p>Hex: {value ?? "(none)"}</p>
 *     {rgb && <p>RGB: {rgb.r}, {rgb.g}, {rgb.b}</p>}
 *     {oklch && <p>OKLCH: L={oklch.l.toFixed(2)} C={oklch.c.toFixed(2)} H={oklch.h.toFixed(0)}°</p>}
 *   </>
 * );
 * ```
 */
export function useAuraColorPicker(ref) {
  const [value, setValue] = useState(null);
  const [rgb, setRgb] = useState(null);
  const [hsl, setHsl] = useState(null);
  const [oklch, setOklch] = useState(null);
  const [alpha, setAlpha] = useState(null);

  useEffect(function () {
    const el = ref && ref.current;
    if (!el) return;
    // Seed initial color model from the value attribute on mount using Aura.color.
    var initVal = el.getAttribute("value");
    if (initVal) {
      setValue(initVal);
      var C = typeof window !== "undefined" && window.Aura && window.Aura.color;
      if (C && typeof C.parseColor === "function") {
        var parsed = C.parseColor(initVal);
        if (parsed) {
          var initRgb = { r: parsed.r, g: parsed.g, b: parsed.b };
          setRgb(initRgb);
          setHsl(C.rgbToHsl(initRgb));
          setOklch(C.rgbToOklch(initRgb));
          setAlpha(typeof parsed.a === "number" ? parsed.a : 1);
        }
      }
    }
    function onChange(e) {
      const d = e.detail || {};
      setValue(d.value || null);
      setRgb(d.rgb || null);
      setHsl(d.hsl || null);
      setOklch(d.oklch || null);
      setAlpha(typeof d.alpha === "number" ? d.alpha : null);
    }
    el.addEventListener("aura:change", onChange);
    return function () {
      el.removeEventListener("aura:change", onChange);
    };
  }, [ref]);

  return { value: value, rgb: rgb, hsl: hsl, oklch: oklch, alpha: alpha };
}

/* -------------------------------------------------------------------------- */
/* useAuraForm                                                                  */
/* -------------------------------------------------------------------------- */

/**
 * Subscribes to form-wide change and dirty events on an `<aura-form>` element.
 *
 * Events:
 * - `aura:form-change` — fired when a managed field changes; `detail.managed`
 *   is the count of fields currently tracked by the form.
 * - `aura:dirty` — fired when the form transitions from clean to dirty
 *   (has unsaved changes); no detail payload.
 *
 * @param {React.RefObject<HTMLElement>} ref — ref attached to the `<aura-form>` element.
 * @returns {{ managed: number|null, dirty: boolean, clearDirty: () => void }}
 *   - `managed` — the last-reported managed field count, seeded from `aura-field[depends-on]` count on mount.
 *   - `dirty` — `true` after the first `aura:dirty` event; seeded from `data-aura-dirty` attribute on mount.
 *   - `clearDirty` — removes `data-aura-dirty`, calls `Aura.formGuard.clear()`, and resets `dirty` to `false`.
 *
 * @example
 * ```jsx
 * const formRef = useRef(null);
 * const { managed, dirty } = useAuraForm(formRef);
 * <AuraForm ref={formRef}>…</AuraForm>
 * {dirty && <p>You have unsaved changes ({managed} field(s) tracked).</p>}
 * ```
 */
export function useAuraForm(ref) {
  const [managed, setManaged] = useState(null);
  const [dirty, setDirty] = useState(false);
  useEffect(function () {
    const el = ref && ref.current;
    if (!el) return;
    // Seed initial managed count from aura-field[depends-on] elements on mount.
    var initialManaged = el.querySelectorAll("aura-field[depends-on]").length;
    if (initialManaged > 0) setManaged(initialManaged);
    // Seed dirty from data-aura-dirty attribute (form may have been marked before hook mounted).
    if (el.hasAttribute("data-aura-dirty")) setDirty(true);
    function onFormChange(e) {
      const d = e.detail || {};
      setManaged(typeof d.managed === "number" ? d.managed : null);
    }
    function onDirty() {
      setDirty(true);
    }
    el.addEventListener("aura:form-change", onFormChange);
    el.addEventListener("aura:dirty", onDirty);
    return function () {
      el.removeEventListener("aura:form-change", onFormChange);
      el.removeEventListener("aura:dirty", onDirty);
    };
  }, [ref]);
  const clearDirty = useCallback(function () {
    const el = ref && ref.current;
    if (el) {
      el.removeAttribute("data-aura-dirty");
      const win = el.ownerDocument && el.ownerDocument.defaultView;
      if (win && win.Aura && win.Aura.formGuard) win.Aura.formGuard.clear(el);
    }
    setDirty(false);
  }, [ref]);
  return { managed: managed, dirty: dirty, clearDirty: clearDirty };
}

/* -------------------------------------------------------------------------- */
/* useAuraEditor                                                                */
/* -------------------------------------------------------------------------- */

/**
 * Subscribes to content-change events on an `<aura-editor>` element.
 *
 * Listens for `aura:change`, which `aura-editor` dispatches on every
 * user-gesture edit with `detail: { html: string, text: string }`.
 * Programmatic `setHTML()` calls are silent and do NOT trigger this event.
 *
 * `html` and `text` are seeded from the element's `getHTML()` / `getText()` getters on
 * mount (seeded even if the editor starts empty). `null` only during SSR.
 * Programmatic `setHTML()` calls do NOT trigger this event — only user gestures do.
 *
 * @param {React.RefObject<HTMLElement>} ref — ref attached to the `<aura-editor>` element.
 * @returns {{ html: string|null, text: string|null }}
 *   - `html` — the editor's current HTML content (seeded on mount; `null` only during SSR).
 *   - `text` — the plain-text equivalent (seeded on mount; `null` only during SSR).
 *
 * @example
 * ```jsx
 * const editorRef = useRef(null);
 * const { html, text } = useAuraEditor(editorRef);
 * return (
 *   <>
 *     <AuraEditor ref={editorRef} name="body" />
 *     <p>Characters: {text != null ? text.length : "…"}</p>
 *     {html && <div dangerouslySetInnerHTML={{ __html: html }} />}
 *   </>
 * );
 * ```
 */
export function useAuraEditor(ref) {
  const [html, setHtml] = useState(null);
  const [text, setText] = useState(null);
  useEffect(function () {
    const el = ref && ref.current;
    if (!el) return;
    // Seed initial HTML and text from the element's public getters on mount.
    if (typeof el.getHTML === "function") setHtml(el.getHTML());
    if (typeof el.getText === "function") setText(el.getText());
    function onChange(e) {
      const d = e.detail || {};
      setHtml(typeof d.html === "string" ? d.html : null);
      setText(typeof d.text === "string" ? d.text : null);
    }
    el.addEventListener("aura:change", onChange);
    return function () { el.removeEventListener("aura:change", onChange); };
  }, [ref]);
  return { html: html, text: text };
}

/* -------------------------------------------------------------------------- */
/* useAuraSwitch                                                                */
/* -------------------------------------------------------------------------- */

/**
 * Subscribes to `aura:change` on an `<aura-switch>` element.
 *
 * @param {React.RefObject<HTMLElement>} ref
 * `checked` is seeded from the `checked` attribute on mount; `null` only during SSR.
 * `toggle()` delegates to the element's own `toggle()` method — fires `aura:change`
 * so the hook state updates automatically.
 *
 * @returns {{ checked: boolean|null, toggle: () => void }}
 *   - `checked` — `true` when the switch is on, `false` when off (seeded on mount; `null` only during SSR).
 *   - `toggle()` — programmatically flip the switch (emits `aura:change`; no-op when disabled or unmounted).
 *
 * @example
 * ```jsx
 * const switchRef = useRef(null);
 * const { checked, toggle } = useAuraSwitch(switchRef);
 * return (
 *   <>
 *     <AuraSwitch ref={switchRef} name="notify" checked />
 *     <button onClick={toggle}>{checked ? "Disable" : "Enable"} notifications</button>
 *     <p>Notifications: {checked ?? "…"}</p>
 *   </>
 * );
 * ```
 */
export function useAuraSwitch(ref) {
  const [checked, setChecked] = useState(null);
  const toggle = useCallback(function () {
    const el = ref && ref.current;
    if (el && typeof el.toggle === "function") el.toggle();
  }, [ref]);
  useEffect(function () {
    const el = ref && ref.current;
    if (!el) return;
    // Read the initial checked state from the attribute on mount.
    setChecked(el.hasAttribute("checked"));
    function onChange(e) {
      const d = e.detail || {};
      setChecked(typeof d.checked === "boolean" ? d.checked : el.hasAttribute("checked"));
    }
    el.addEventListener("aura:change", onChange);
    return function () { el.removeEventListener("aura:change", onChange); };
  }, [ref]);
  return { checked: checked, toggle: toggle };
}

/* -------------------------------------------------------------------------- */
/* useAuraCheckbox                                                              */
/* -------------------------------------------------------------------------- */

/**
 * Subscribes to `aura:change` on an `<aura-checkbox>` element.
 *
 * @param {React.RefObject<HTMLElement>} ref
 * All fields are seeded from attributes on mount; `null` only during SSR.
 *
 * @param {React.RefObject<HTMLElement>} ref
 * @returns {{ checked: boolean|null, indeterminate: boolean|null, value: string|null }}
 *   - `checked` — `true`/`false` (seeded from `checked` attribute on mount; `null` only during SSR).
 *   - `indeterminate` — `true` when the checkbox has mixed state (seeded on mount).
 *   - `value` — the static `value` attribute (seeded on mount).
 *
 * @example
 * ```jsx
 * const cbRef = useRef(null);
 * const { checked, indeterminate } = useAuraCheckbox(cbRef);
 * return (
 *   <>
 *     <AuraCheckbox ref={cbRef} name="accept" value="yes" checked />
 *     {indeterminate ? <p>Mixed</p> : <p>{checked ? "Accepted" : "Not accepted"}</p>}
 *   </>
 * );
 * ```
 */
export function useAuraCheckbox(ref) {
  const [checked, setChecked] = useState(null);
  const [indeterminate, setIndeterminate] = useState(null);
  const [value, setValue] = useState(null);
  useEffect(function () {
    const el = ref && ref.current;
    if (!el) return;
    // Seed initial state from attributes on mount.
    setChecked(el.hasAttribute("checked"));
    setIndeterminate(el.hasAttribute("indeterminate"));
    setValue(el.getAttribute("value"));
    function onChange(e) {
      const d = e.detail || {};
      setChecked(typeof d.checked === "boolean" ? d.checked : el.hasAttribute("checked"));
      setIndeterminate(typeof d.indeterminate === "boolean" ? d.indeterminate : el.hasAttribute("indeterminate"));
      setValue(typeof d.value === "string" ? d.value : el.getAttribute("value"));
    }
    el.addEventListener("aura:change", onChange);
    return function () { el.removeEventListener("aura:change", onChange); };
  }, [ref]);
  return { checked: checked, indeterminate: indeterminate, value: value };
}

/* -------------------------------------------------------------------------- */
/* useAuraSelect                                                                */
/* -------------------------------------------------------------------------- */

/**
 * Subscribes to `aura:change` on an `<aura-select>` element.
 *
 * The return type reflects both single and multi-select modes:
 * - Single mode: `value` is a `string`, `multiple` is `false`.
 * - Multi mode: `value` is a `string[]`, `multiple` is `true`.
 *
 * All fields are seeded from the element's attributes and DOM on mount; `null` only during SSR.
 *
 * @param {React.RefObject<HTMLElement>} ref
 * @returns {{ value: string|string[]|null, label: string|null, multiple: boolean }}
 *   - `value` — the selected value(s); seeded on mount from attribute/DOM; `null` only during SSR.
 *   - `label` — the display label of the selected option(s); seeded on mount; `null` only during SSR.
 *   - `multiple` — `true` when the select is in multi-select mode (seeded on mount).
 *
 * @example
 * ```jsx
 * const selRef = useRef(null);
 * const { value, label } = useAuraSelect(selRef);
 * return (
 *   <>
 *     <AuraSelect ref={selRef} name="fruit" value="apple">
 *       <option value="apple">Apple</option>
 *       <option value="banana">Banana</option>
 *     </AuraSelect>
 *     <p>Selected: {label ?? "…"}</p>
 *   </>
 * );
 * ```
 */
export function useAuraSelect(ref) {
  const [value, setValue] = useState(null);
  const [label, setLabel] = useState(null);
  const [multiple, setMultiple] = useState(false);
  useEffect(function () {
    const el = ref && ref.current;
    if (!el) return;
    // Seed initial state from the element on mount.
    var isMultiple = el.hasAttribute("multiple");
    setMultiple(isMultiple);
    var initVal = el.getAttribute("value");
    if (initVal !== null) setValue(isMultiple ? initVal.split(",").map(function (s) { return s.trim(); }) : initVal);
    // Seed label from the selected option's text content.
    var selectedOpt = el.querySelector("aura-option[selected]");
    if (selectedOpt) setLabel(selectedOpt.textContent.trim() || null);
    function onChange(e) {
      const d = e.detail || {};
      setValue(d.value !== undefined ? d.value : null);
      setLabel(typeof d.label === "string" ? d.label : null);
      setMultiple(d.multiple === true);
    }
    el.addEventListener("aura:change", onChange);
    return function () { el.removeEventListener("aura:change", onChange); };
  }, [ref]);
  return { value: value, label: label, multiple: multiple };
}

/* -------------------------------------------------------------------------- */
/* useAuraStepper                                                               */
/* -------------------------------------------------------------------------- */

/**
 * Subscribes to `aura:change` on an `<aura-stepper>` element.
 *
 * `value` is seeded from the `value` attribute on mount (or `min` / 0 when no `value` is set);
 * `null` only during SSR.
 *
 * @param {React.RefObject<HTMLElement>} ref
 * @returns {{ value: number|null }}
 *   - `value` — the current numeric value (seeded on mount from `value` attr or `min`; `null` only during SSR).
 *
 * @example
 * ```jsx
 * const stepperRef = useRef(null);
 * const { value } = useAuraStepper(stepperRef);
 * return (
 *   <>
 *     <AuraStepper ref={stepperRef} min={0} max={10} value={3} />
 *     <p>Count: {value ?? "…"}</p>
 *   </>
 * );
 * ```
 */
export function useAuraStepper(ref) {
  const [value, setValue] = useState(null);
  useEffect(function () {
    const el = ref && ref.current;
    if (!el) return;
    var initVal = el.getAttribute("value");
    if (initVal !== null) {
      var n = parseFloat(initVal);
      if (!isNaN(n)) setValue(n);
    } else {
      // Fall back to min attribute (default 0) when no value is set.
      var minAttr = el.getAttribute("min");
      var minVal = minAttr !== null ? parseFloat(minAttr) : 0;
      if (!isNaN(minVal)) setValue(minVal);
    }
    function onChange(e) {
      const d = e.detail || {};
      setValue(typeof d.value === "number" ? d.value : null);
    }
    el.addEventListener("aura:change", onChange);
    return function () { el.removeEventListener("aura:change", onChange); };
  }, [ref]);
  return { value: value };
}

/* -------------------------------------------------------------------------- */
/* useAuraRange                                                                 */
/* -------------------------------------------------------------------------- */

/**
 * Subscribes to `aura:change` on an `<aura-range>` element.
 *
 * Handles both single-thumb and dual-thumb (range) modes:
 * - Single mode: `value` is a `number`.
 * - Dual mode (when `range` attribute is set): `value` is `[lo, hi]`.
 *
 * `value` is seeded from the `value` attribute on mount (falls back to `min`/`[min,max]`);
 * `null` only during SSR.
 *
 * @param {React.RefObject<HTMLElement>} ref
 * @returns {{ value: number|number[]|null }}
 *   - `value` — current value(s), seeded on mount; `null` only during SSR.
 *     Single mode: `number`. Dual (`range` attr set): `[lo, hi]`.
 *
 * @example
 * ```jsx
 * const rangeRef = useRef(null);
 * const { value } = useAuraRange(rangeRef);
 * return (
 *   <>
 *     <AuraRange ref={rangeRef} min={0} max={100} step={5} value={40} />
 *     <p>Value: {value ?? "…"}</p>
 *     {/* Dual mode: <AuraRange range min={0} max={100} value="20,80" /> *\/}
 *     {/* value is [20, 80] — render as `${value[0]}–${value[1]}` *\/}
 *   </>
 * );
 * ```
 */
export function useAuraRange(ref) {
  const [value, setValue] = useState(null);
  useEffect(function () {
    const el = ref && ref.current;
    if (!el) return;
    // Seed from the value attribute on mount — handles both single and "lo,hi" dual mode.
    var minAttr = parseFloat(el.getAttribute("min") || "0") || 0;
    var maxAttr = parseFloat(el.getAttribute("max") || "100") || 100;
    var initVal = el.getAttribute("value");
    var isDual = el.hasAttribute("range");
    if (initVal !== null) {
      var parts = String(initVal).split(/[,\s]+/).filter(function (s) { return s !== ""; });
      if (parts.length >= 2 || isDual) {
        var lo = parseFloat(parts[0] || String(minAttr)), hi = parseFloat(parts[1] || String(maxAttr));
        if (!isNaN(lo) && !isNaN(hi)) setValue([lo, hi]);
      } else {
        var n = parseFloat(initVal);
        if (!isNaN(n)) setValue(n);
      }
    } else if (isDual) {
      // No value set; dual range defaults to [min, max].
      setValue([minAttr, maxAttr]);
    } else {
      // No value set; single range defaults to min.
      setValue(minAttr);
    }
    function onChange(e) {
      const d = e.detail || {};
      setValue(d.value !== undefined ? d.value : null);
    }
    el.addEventListener("aura:change", onChange);
    return function () { el.removeEventListener("aura:change", onChange); };
  }, [ref]);
  return { value: value };
}

/* -------------------------------------------------------------------------- */
/* useAuraCopy                                                                  */
/* -------------------------------------------------------------------------- */

/**
 * Subscribes to `aura:copy` on an element (or its `data-aura-copy` trigger).
 *
 * Fired by `copy.js` whenever the copy-to-clipboard action completes
 * (after the 1.6 s "Copied" animation begins). `detail.text` is the
 * string that was written to the clipboard.
 *
 * @param {React.RefObject<HTMLElement>} ref — ref attached to the container
 *   (typically the parent of `<AuraCopyButton>` so the bubbled event lands here,
 *   OR the `<AuraCopyButton>` element itself).
 * @returns {{ text: string|null }}
 *   - `text` — the last-copied text, or `null` before the first copy action.
 *
 * @example
 * ```jsx
 * const wrapRef = useRef(null);
 * const { text } = useAuraCopy(wrapRef);
 * <div ref={wrapRef}>
 *   <AuraCopyButton copyText="npm install @aura-design/core">Copy</AuraCopyButton>
 * </div>
 * {text && <p>Copied: {text}</p>}
 * ```
 */
export function useAuraCopy(ref) {
  const [text, setText] = useState(null);
  useEffect(function () {
    const el = ref && ref.current;
    if (!el) return;
    function onCopy(e) {
      const d = e.detail || {};
      setText(typeof d.text === "string" ? d.text : null);
    }
    el.addEventListener("aura:copy", onCopy);
    return function () { el.removeEventListener("aura:copy", onCopy); };
  }, [ref]);
  const copy = useCallback(function (str) {
    var api = window.Aura && window.Aura.copy;
    return api ? api.copyText(str) : Promise.resolve(false);
  }, []);
  return { text: text, copy: copy };
}

/* -------------------------------------------------------------------------- */
/* useAuraFooter                                                                */
/* -------------------------------------------------------------------------- */

/**
 * Subscribes to `aura:footer-revealed` on an `<aura-footer>` element.
 *
 * Fired by `footer.js` when the footer transitions between its revealed
 * (scrolled-into-view) and hidden states. Useful for adapting a floating
 * action button or bottom chrome when the footer becomes visible.
 *
 * @param {React.RefObject<HTMLElement>} ref — ref attached to the `<AuraFooter>` element.
 * @returns {{ revealed: boolean|null }}
 *   - `revealed` — `true` when the footer is revealed, `false` when hidden,
 *     `null` before the first transition.
 *
 * @example
 * ```jsx
 * const footerRef = useRef(null);
 * const { revealed } = useAuraFooter(footerRef);
 * <AuraFooter ref={footerRef} data-aura-footer="reveal" />
 * {revealed && <p>Footer is visible</p>}
 * ```
 */
export function useAuraFooter(ref) {
  const [revealed, setRevealed] = useState(null);
  useEffect(function () {
    const el = ref && ref.current;
    if (!el) return;
    // Seed initial state from the revealed attribute on mount.
    if (el.hasAttribute("data-aura-revealed")) setRevealed(true);
    function onReveal(e) {
      const d = e.detail || {};
      setRevealed(typeof d.revealed === "boolean" ? d.revealed : null);
    }
    el.addEventListener("aura:footer-revealed", onReveal);
    return function () { el.removeEventListener("aura:footer-revealed", onReveal); };
  }, [ref]);
  return { revealed: revealed };
}

/* -------------------------------------------------------------------------- */
/* useAuraNavPanel                                                              */
/* -------------------------------------------------------------------------- */

/**
 * Subscribes to `aura:nav-panel-open` on an `<aura-nav-header>` element.
 *
 * Fired by `nav-header.js` when a nav panel (flyout menu) opens.
 * `detail.trigger` is the DOM element that triggered the open (a nav item
 * or button). Useful for analytics, focus management, or synchronising
 * external state with the nav panel lifecycle.
 *
 * @param {React.RefObject<HTMLElement>} ref — ref attached to the `<AuraNavHeader>` element.
 * @returns {{ trigger: Element|null }}
 *   - `trigger` — the element that triggered the last panel open,
 *     or `null` before the first open event.
 *
 * @example
 * ```jsx
 * const navRef = useRef(null);
 * const { trigger } = useAuraNavPanel(navRef);
 * <AuraNavHeader ref={navRef}>…</AuraNavHeader>
 * {trigger && <p>Nav opened by: {trigger.textContent}</p>}
 * ```
 */
export function useAuraNavPanel(ref) {
  const [trigger, setTrigger] = useState(null);
  useEffect(function () {
    const el = ref && ref.current;
    if (!el) return;
    function onOpen(e) {
      const d = e.detail || {};
      setTrigger(d.trigger instanceof Element ? d.trigger : null);
    }
    el.addEventListener("aura:nav-panel-open", onOpen);
    return function () { el.removeEventListener("aura:nav-panel-open", onOpen); };
  }, [ref]);
  return { trigger: trigger };
}

/* -------------------------------------------------------------------------- */
/* useAuraTagInput                                                              */
/* -------------------------------------------------------------------------- */

/**
 * Subscribes to `aura:change` on an `<aura-tag-input>` element.
 *
 * Fired whenever a tag is added or removed. `detail.tags` is the complete
 * current tag array at the time of the event.
 *
 * @param {React.RefObject<HTMLElement>} ref
 * @returns {{ tags: string[]|null, addTag: (value: string) => void, removeTag: (index: number) => void }}
 *   - `tags` — the current tag array (seeded from `value` attribute on mount); `null` only during SSR.
 *   - `addTag(value)` — add a tag (dedupes and trims; no-op on empty/duplicate).
 *   - `removeTag(index)` — remove the tag at `index`.
 *
 * @example
 * ```jsx
 * const tagRef = useRef(null);
 * const { tags, addTag, removeTag } = useAuraTagInput(tagRef);
 * return (
 *   <>
 *     <AuraTagInput ref={tagRef} placeholder="Add tag…" value="react,css" />
 *     <p>Tags: {tags ? tags.join(", ") : "…"}</p>
 *     <button type="button" onClick={() => addTag("typescript")}>+ typescript</button>
 *     <button type="button" onClick={() => removeTag(0)}>Remove first</button>
 *   </>
 * );
 * ```
 */
export function useAuraTagInput(ref) {
  const [tags, setTags] = useState(null);
  useEffect(function () {
    const el = ref && ref.current;
    if (!el) return;
    // Seed initial tags from the value attribute on mount.
    var initVal = el.getAttribute("value");
    if (initVal !== null) setTags(initVal ? initVal.split(",").map(function (s) { return s.trim(); }) : []);
    function onChange(e) {
      const d = e.detail || {};
      setTags(Array.isArray(d.tags) ? d.tags.slice() : null);
    }
    el.addEventListener("aura:change", onChange);
    return function () { el.removeEventListener("aura:change", onChange); };
  }, [ref]);
  const addTag = useCallback(function (value) {
    const el = ref && ref.current;
    if (el && typeof el.addTag === "function") el.addTag(value);
  }, [ref]);
  const removeTag = useCallback(function (index) {
    const el = ref && ref.current;
    if (el && typeof el.removeTag === "function") el.removeTag(index);
  }, [ref]);
  return { tags: tags, addTag: addTag, removeTag: removeTag };
}

/* -------------------------------------------------------------------------- */
/* useAuraRadio                                                                 */
/* -------------------------------------------------------------------------- */

/**
 * Subscribes to `aura:change` on an `<aura-radio>` element.
 *
 * Fired when the radio button is checked. `detail.checked` is `true` on check
 * (a radio button cannot be unchecked by clicking; deselection occurs when
 * another radio in the same group is checked). `detail.value` is the radio's
 * `value` attribute.
 *
 * **Tip:** for a radio group, attach this hook to each `<aura-radio>` and use
 * the `value` from whichever fires an event with `checked: true`.
 *
 * `checked` and `value` are seeded from attributes on mount; `null` only during SSR.
 *
 * @param {React.RefObject<HTMLElement>} ref
 * @returns {{ checked: boolean|null, value: string|null }}
 *   - `checked` — `true` when this radio is checked (seeded on mount; `null` only during SSR).
 *   - `value` — the radio's static `value` attribute (seeded on mount; `null` only during SSR).
 *
 * @example
 * ```jsx
 * const radioRef = useRef(null);
 * const { checked, value } = useAuraRadio(radioRef);
 * return (
 *   <>
 *     <AuraRadio ref={radioRef} name="size" value="lg" />
 *     {checked && <p>{value} selected</p>}
 *   </>
 * );
 * ```
 */
export function useAuraRadio(ref) {
  const [checked, setChecked] = useState(null);
  const [value, setValue] = useState(null);
  useEffect(function () {
    const el = ref && ref.current;
    if (!el) return;
    // Seed initial state from attributes on mount.
    setChecked(el.hasAttribute("checked"));
    setValue(el.getAttribute("value"));
    function onChange(e) {
      const d = e.detail || {};
      setChecked(typeof d.checked === "boolean" ? d.checked : el.hasAttribute("checked"));
      setValue(typeof d.value === "string" ? d.value : el.getAttribute("value"));
    }
    el.addEventListener("aura:change", onChange);
    return function () { el.removeEventListener("aura:change", onChange); };
  }, [ref]);
  return { checked: checked, value: value };
}
